// src/components/Navbar.js
import React from 'react';
import { Link } from 'react-router-dom';
import './Navbar.css'; // Importando o CSS para estilos

const Navbar = () => {
  return (
    <nav className="navbar">
      <div className="navbar-logo">ProJuris</div>
      <ul className="navbar-links">
        <li><Link to="/">Gestão</Link></li>
        <li><Link to="/atividades">Atividades</Link></li>
        <li><Link to="/processos">Processos</Link></li>
        <li><Link to="/financeiro">Financeiro</Link></li>
        <li><Link to="/documentos">Documentos</Link></li>
      </ul>
    </nav>
  );
};

export default Navbar;
